Code.NativeIaC:
```bicep
// AKS cluster with Microsoft Defender security monitoring enabled
resource aks 'Microsoft.ContainerService/managedClusters@2024-05-01' = {
  name: '<CLUSTER_NAME>'
  location: '<LOCATION>'
  identity: {
    type: 'SystemAssigned'
  }
  properties: {
    dnsPrefix: '<DNS_PREFIX>'
    securityProfile: {
      defender: {
        logAnalyticsWorkspaceResourceId: '<LOG_ANALYTICS_WORKSPACE_RESOURCE_ID>'
        securityMonitoring: {
          enabled: true // Critical: enables Defender security monitoring for AKS
        }
      }
    }
    agentPoolProfiles: [
      {
        name: 'system'
        count: 1
        vmSize: 'Standard_DS2_v2'
        mode: 'System'
      }
    ]
  }
}
```

Code.Terraform:
```hcl
resource "azurerm_log_analytics_workspace" "example" {
  name                = "<workspace-name>"
  location            = "<location>"
  resource_group_name = "<resource-group>"
  sku                 = "PerGB2018"
}

resource "azurerm_kubernetes_cluster" "example" {
  name                = "<cluster-name>"
  location            = "<location>"
  resource_group_name = "<resource-group>"
  dns_prefix          = "<dns-prefix>"

  default_node_pool {
    name       = "system"
    node_count = 1
    vm_size    = "Standard_DS2_v2"
  }

  identity {
    type = "SystemAssigned"
  }

  microsoft_defender {
    log_analytics_workspace_id = azurerm_log_analytics_workspace.example.id
  }
}
```
